using UnityEngine;

/// <summary>
/// Checkpoint temporário (leve, sem menu de save — Tarefa "Morte e
/// checkpoints"): ao entrar no alcance, regista a posição deste objecto como
/// "checkpoint temporário" da área actual (<see cref="PlayerProgress.SetTemporaryCheckpoint"/>).
/// <see cref="PlayerDeathHandler"/> usa este checkpoint (em vez do último
/// Refúgio Seguro — <see cref="SafeHaven"/>) para reaparecer, enquanto o
/// jogador permanecer na mesma área.
///
/// Diferenças vs SafeHaven: não abre o menu de save, não é persistido no
/// ficheiro de save (apenas durante a sessão actual) e é substituído pelo
/// checkpoint temporário seguinte (de outra área activa).
///
/// ⚠ COMPORTAMENTO DE PERSISTÊNCIA (importante para QA):
/// Este checkpoint é APENAS de sessão. Se o jogador passar por um Checkpoint,
/// gravar num SafeHaven, fechar o jogo e reabrir, o respawn acontecerá no
/// SafeHaven — não neste Checkpoint. Isto é o comportamento correcto/
/// intencional (checkpoints temporários não substituem saves manuais). NÃO é
/// um bug a reportar.
///
/// Usos típicos:
/// - "Checkpoint de início de área": um Checkpoint perto da entrada de cada
///   área (sem "requiredSpiritItem" — sempre activo).
/// - "Caminho do Ferimento": dividido em 6 sub-áreas (uma por mundo). Em cada
///   sub-área, coloca-se um Checkpoint com "requiredSpiritItem" = o "Espírito
///   Final" desse mundo (<see cref="WorldData.finalSpiritItem"/>). O checkpoint
///   só fica activo (e só é guardado) se o jogador já tiver recolhido esse
///   item; caso contrário esta sub-área não regista checkpoint de início.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class Checkpoint : MonoBehaviour
{
    [Header("Identidade")]
    [Tooltip("Nome a mostrar no feedback (opcional).")]
    public string displayName;

    [Header("Condição (opcional — Caminho do Ferimento)")]
    [Tooltip("Se definido, este checkpoint só fica activo se o jogador já tiver recolhido este item especial (ex: WorldData.finalSpiritItem do mundo correspondente). Vazio = sempre activo.")]
    public ItemData requiredSpiritItem;

    [Header("Feedback Visual/Sonoro (opcional)")]
    [Tooltip("Activado na primeira vez que o checkpoint é registado (ex: brilho/runa).")]
    public SpriteRenderer glowSprite;

    [Tooltip("Som tocado na primeira vez que o checkpoint é registado.")]
    public AudioClip activateSfx;

    private bool _activated;

    private void OnTriggerEnter2D(Collider2D other)
    {
        TryActivate(other);
    }

    private void OnTriggerStay2D(Collider2D other)
    {
        // Idempotente: garante o registo se o jogador já estava dentro ao carregar a cena.
        // Após a primeira activação o valor não muda, por isso saímos cedo.
        if (_activated) return;
        TryActivate(other);
    }

    private void TryActivate(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        var progress = PlayerProgress.Instance;
        if (progress == null) return;

        if (requiredSpiritItem != null && !progress.HasCollectedSpecialItem(requiredSpiritItem))
            return;

        var area = WorldState.Instance != null ? WorldState.Instance.CurrentArea : null;
        if (area == null || string.IsNullOrEmpty(area.areaId)) return;

        progress.SetTemporaryCheckpoint(area.areaId, transform.position);

        if (!_activated)
        {
            _activated = true;
            if (glowSprite != null) glowSprite.enabled = true;
            if (activateSfx != null) AudioManager.Instance?.PlaySE(activateSfx);
        }
    }
}
